        .faction-modal-content { background: linear-gradient(145deg, rgba(25, 20, 30, 0.95), rgba(15, 10, 15, 0.98)); border: 1px solid var(--border-metal); border-top: 2px solid var(--accent-gold); border-bottom: 2px solid var(--accent-gold); border-radius: 8px; width: 80%; max-width: 350px; padding: 25px; box-shadow: 0 0 40px rgba(0,0,0,0.9), inset 0 0 20px rgba(255, 215, 0, 0.05); position: relative; animation: faction-pop 0.4s cubic-bezier(0.2, 0.8, 0.2, 1.1); text-align: center; }
        .faction-modal-close { position: absolute; top: 8px; right: 15px; color: var(--text-dim); font-size: 28px; cursor: pointer; transition: 0.3s; line-height: 1; }
