        .faction-modal-header { font-size: 1.3em; font-weight: bold; color: var(--accent-gold); margin-bottom: 15px; padding-bottom: 12px; border-bottom: 1px dashed rgba(255, 255, 255, 0.1); text-shadow: 0 0 8px var(--accent-gold-glow); letter-spacing: 2px; }
