    /* 获取立绘URL（支持多图切换和玉简同步） */
    function getPortraitUrl(name, gender) {
        try { const saved = localStorage.getItem('daoyuan_custom_portraits'); if (saved) { const cp = JSON.parse(saved); if (cp[name]) return cp[name].split('|')[0]; } } catch(e) {}
        if (charPortraitsFemale[name] && gender && /^女/.test(gender)) {
            return charPortraitsFemale[name];
        }
        return charPortraits[name] ? String(charPortraits[name]).split('|')[0] : undefined;
    }

    /* 从 localStorage 加载自定义立绘并合并 */
    (function() {
        try {
            const saved = localStorage.getItem('daoyuan_custom_portraits');
            if (saved) {
                const customPortraits = JSON.parse(saved);
                Object.assign(charPortraits, customPortraits);
            }
        } catch(e) {
            console.warn('[道渊] 加载自定义立绘失败:', e);
        }
    })();

    /* 保存自定义立绘到 localStorage */
    window.saveCustomPortrait = function(name, url) {
        try {
            let customPortraits = {};
            const saved = localStorage.getItem('daoyuan_custom_portraits');
            if (saved) {
                customPortraits = JSON.parse(saved);
            }
            customPortraits[name] = url;
            const dataStr = JSON.stringify(customPortraits);
            if (url && url.startsWith('data:') && url.length > 2 * 1024 * 1024) {
                console.warn('[道渊] 单张立绘过大(' + (url.length/1024/1024).toFixed(1) + 'MB)，建议压缩图片或使用图床');
            }
            if (dataStr.length > 3 * 1024 * 1024) {
                alert('⚠️ 立绘数据过大（' + (dataStr.length/1024/1024).toFixed(1) + 'MB），已接近localStorage上限(5MB)。建议使用图床URL而非本地图片，或删除部分自定义立绘。');
            }
            if (dataStr.length > 4.5 * 1024 * 1024) {
                alert('⚠️ 立绘数据超过4.5MB，localStorage可能无法保存！请立即使用图床URL替代本地图片。');
                return false;
            }
            localStorage.setItem('daoyuan_custom_portraits', dataStr);
            charPortraits[name] = url;
            if (typeof populateCharacterData === 'function') {
                populateCharacterData();
            }
            return true;
        } catch(e) {
            console.warn('[道渊] 保存自定义立绘失败:', e);
            if (e.name === 'QuotaExceededError') {
                alert('⚠️ 存储空间不足！本地图片过多，请使用图床URL（如 catbox.moe）替代，或删除一些不需要的自定义立绘。');
            } else {
                alert('保存失败：' + e.message);
            }
            return false;
        }
    };

    /* 处理本地图片上传 */
    window.handlePortraitFileUpload = function(fileInput, charName) {
        const file = fileInput.files[0];
        if (!file) return;
        if (file.size > 5 * 1024 * 1024) {
            alert('图片文件过大，请选择小于5MB的图片（建议使用图床URL）');
            return;
        }
        if (!file.type.startsWith('image/')) {
            alert('请选择有效的图片文件');
            return;
        }
        const fileNameSpan = document.getElementById('portrait-file-name');
        if (fileNameSpan) {
            fileNameSpan.textContent = '📷 ' + file.name + ' (' + (file.size/1024).toFixed(1) + 'KB)';
            fileNameSpan.style.color = '#64ff8a';
        }
        const reader = new FileReader();
        reader.onload = function(e) {
            const base64 = e.target.result;
            const previewImg = document.getElementById('portrait-preview-img');
            if (previewImg) {
                previewImg.src = base64;
                previewImg.classList.add('show');
                previewImg.onerror = null;
            }
            const urlInput = document.getElementById('portrait-url-input');
            if (urlInput) {
                urlInput.value = base64;
            }
        };
        reader.readAsDataURL(file);
    };

    /* 删除自定义立绘（恢复默认） */
    window.removeCustomPortrait = function(name) {
        try {
            let customPortraits = {};
            const saved = localStorage.getItem('daoyuan_custom_portraits');
            if (saved) {
                customPortraits = JSON.parse(saved);
            }
            delete customPortraits[name];
            localStorage.setItem('daoyuan_custom_portraits', JSON.stringify(customPortraits));
            if (typeof populateCharacterData === 'function') {
                populateCharacterData();
            }
            return true;
        } catch(e) {
            console.warn('[道渊] 删除自定义立绘失败:', e);
            return false;
        }
    };

    /* 打开自定义立绘弹窗 */
    window.openCustomPortraitDialog = function(charName) {
        const existing = document.getElementById('portrait-custom-modal');
        if (existing) existing.remove();

        const currentUrl = charPortraits[charName] || '';
        const isCustom = (function() {
            try {
                const saved = localStorage.getItem('daoyuan_custom_portraits');
                if (saved) {
                    const cp = JSON.parse(saved);
                    return cp.hasOwnProperty(charName);
                }
            } catch(e) {}
            return false;
        })();

        const modal = document.createElement('div');
        modal.id = 'portrait-custom-modal';
        modal.className = 'portrait-custom-modal show';
        modal.innerHTML = `
            <div class="portrait-custom-dialog">
                <h3>🎨 自定义立绘 - ${charName}</h3>
                <img class="portrait-preview" id="portrait-preview-img" alt="预览" style="display:none;" onerror="this.style.display='none'">
                <div style="display:flex;gap:8px;align-items:stretch;margin-bottom:12px;">
                    <label for="portrait-file-input" class="portrait-file-label">📁 选择本地图片</label>
                    <input type="file" id="portrait-file-input" accept="image/*" style="display:none;" onchange="window.handlePortraitFileUpload(this, '${charName}')">
                    <span id="portrait-file-name" style="flex:1;display:flex;align-items:center;color:var(--text-dim);font-size:0.8em;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">或输入URL地址</span>
                </div>
                <label>图片URL地址</label>
                <input type="text" id="portrait-url-input" placeholder="请输入立绘图片的URL地址（支持常见图床）" value="${currentUrl}">
                <div class="portrait-custom-hint">💡 支持上传本地图片（自动保存），或粘贴图床链接（catbox.moe、postimg.cc等）</div>
                <div class="btn-row">
                    <button class="btn-confirm" id="portrait-confirm-btn">✅ 确认保存</button>
                    ${isCustom ? '<button class="btn-reset" id="portrait-reset-btn">🔄 恢复默认</button>' : ''}
                    <button class="btn-cancel" id="portrait-cancel-btn">取消</button>
                </div>
            </div>
        `;
        document.body.appendChild(modal);

        const previewImgEl = modal.querySelector('#portrait-preview-img');
        if (currentUrl) {
            previewImgEl.src = currentUrl;
            previewImgEl.classList.add('show');
            previewImgEl.style.display = '';
        }

        const urlInput = modal.querySelector('#portrait-url-input');
        const previewImg = modal.querySelector('#portrait-preview-img');
        urlInput.addEventListener('input', function() {
            const val = this.value.trim();
            if (val) {
                previewImg.src = val;
                previewImg.classList.add('show');
            } else {
                previewImg.classList.remove('show');
            }
        });

        modal.querySelector('#portrait-confirm-btn').addEventListener('click', function() {
            const url = urlInput.value.trim();
            if (!url) {
                alert('请输入有效的图片URL地址');
                return;
            }
            if (window.saveCustomPortrait(charName, url)) {
                const prevImg = modal.querySelector('#portrait-preview-img');
                if (prevImg) { prevImg.src = ''; prevImg.removeAttribute('src'); }
                modal.remove();
            } else {
                alert('保存失败，请重试');
            }
        });

        modal.querySelector('#portrait-cancel-btn').addEventListener('click', function() {
            const prevImg = modal.querySelector('#portrait-preview-img');
            if (prevImg) { prevImg.src = ''; prevImg.removeAttribute('src'); }
            modal.remove();
        });

        const resetBtn = modal.querySelector('#portrait-reset-btn');
        if (resetBtn) {
            resetBtn.addEventListener('click', function() {
                if (confirm('确定要恢复「' + charName + '」的默认立绘吗？')) {
                    window.removeCustomPortrait(charName);
                    const prevImg = modal.querySelector('#portrait-preview-img');
                    if (prevImg) { prevImg.src = ''; prevImg.removeAttribute('src'); }
                    modal.remove();
                    if (confirm('需要刷新页面以完全恢复默认立绘，是否刷新？')) {
                        location.reload();
                    }
                }
            });
        }

        modal.addEventListener('click', function(e) {
            if (e.target === modal) {
                const prevImg = modal.querySelector('#portrait-preview-img');
                if (prevImg) { prevImg.src = ''; prevImg.removeAttribute('src'); }
                modal.remove();
            }
        });

        setTimeout(() => urlInput.focus(), 100);
    };

    window.appendChatMessage = async function(charName, sender, content) {
        try {
            const lastMsgId = getLastMessageId();
            const messages = getChatMessages('0-' + lastMsgId, { role: 'assistant' });
            if (!messages || messages.length === 0) {
                console.warn('找不到消息历史');
                return;
            }
            const targetMsgId = messages[messages.length - 1].message_id;

            if (window.Mvu && typeof Mvu.replaceMvuData === 'function') {
                const fullData = Mvu.getMvuData({ type: 'message', message_id: targetMsgId });
                if (fullData && fullData.stat_data && fullData.stat_data.玉简) {
                    if (!fullData.stat_data.玉简[charName]) {
                        fullData.stat_data.玉简[charName] = { 历史记录: {} };
                    }
                    const history = fullData.stat_data.玉简[charName].历史记录 || {};
                    const newMsgId = 'msg_' + Date.now() + Math.floor(Math.random() * 1000);
                    const now = new Date();
                    const timeStr = now.getHours().toString().padStart(2, '0') + ':' + now.getMinutes().toString().padStart(2, '0');

                    history[newMsgId] = {
                        "发送者": sender,
                        "内容": content,
                        "时间": timeStr
                    };

                    fullData.stat_data.玉简[charName].历史记录 = history;
                    await Mvu.replaceMvuData(fullData, { type: 'message', message_id: targetMsgId });
                    if(typeof populateCharacterData === 'function') populateCharacterData();
                }
            } else {
                 console.warn('MVU 未初始化');
            }
        } catch (err) {
            console.error('[道渊状态栏] 更新玉简消息失败:', err);
        }
    };

    /* --- 更新调试日志显示 --- */
    window.updateDebugLog = function(logContent) {
        const logBox = document.getElementById('wx-debug-log');
        if (logBox) {
            const now = new Date();
            const timeStr = now.getHours().toString().padStart(2, '0') + ':' + now.getMinutes().toString().padStart(2, '0') + ':' + now.getSeconds().toString().padStart(2, '0');
            logBox.value = `[${timeStr}] 原始返回:\n${logContent}\n\n` + logBox.value;
        }
    };

    /* --- 玉简设定及预设功能 --- */
    window.loadPresets = function() {
        const select = document.getElementById('wx-preset-select');
        if (!select) return;
        select.innerHTML = '<option value="">-- 当前手动配置 --</option>';
        try {
            const saved = localStorage.getItem('daoyuan_wx_presets');
            if (saved) {
                const presets = JSON.parse(saved);
                for (const name in presets) {
                    const opt = document.createElement('option');
                    opt.value = name;
                    opt.textContent = name;
                    select.appendChild(opt);
                }
            }
        } catch(e) { console.error('加载预设失败:', e); }
    };

    window.applyPreset = function(presetName) {
        if (!presetName) return;
        try {
            const saved = localStorage.getItem('daoyuan_wx_presets');
            if (saved) {
                const presets = JSON.parse(saved);
                const p = presets[presetName];
                if (p) {
                    if (document.getElementById('wx-custom-prompt')) document.getElementById('wx-custom-prompt').value = p.customPrompt || '';
                    if (document.getElementById('wx-api-url')) document.getElementById('wx-api-url').value = p.apiBaseUrl || '';
                    if (document.getElementById('wx-api-key')) document.getElementById('wx-api-key').value = p.apiKey || '';
                    if (document.getElementById('wx-api-model')) document.getElementById('wx-api-model').value = p.apiModel || '';
                }
            }
        } catch(e) {}
    };

    window.saveAsPreset = function() {
        const name = prompt("请输入预设名称：\n(若名称已存在将覆盖原预设)");
        if (!name) return;
        try {
            let presets = {};
            const saved = localStorage.getItem('daoyuan_wx_presets');
            if (saved) presets = JSON.parse(saved);

            presets[name] = {
                customPrompt: document.getElementById('wx-custom-prompt') ? document.getElementById('wx-custom-prompt').value : '',
                apiBaseUrl: document.getElementById('wx-api-url') ? document.getElementById('wx-api-url').value.trim() : '',
                apiKey: document.getElementById('wx-api-key') ? document.getElementById('wx-api-key').value.trim() : '',
                apiModel: document.getElementById('wx-api-model') ? document.getElementById('wx-api-model').value.trim() : ''
            };

            localStorage.setItem('daoyuan_wx_presets', JSON.stringify(presets));
            window.loadPresets();
            document.getElementById('wx-preset-select').value = name;
            alert(`预设 "${name}" 已保存！`);
        } catch(e) {
            alert("保存预设失败：" + e.message);
        }
    };

    window.deletePreset = function() {
        const select = document.getElementById('wx-preset-select');
        const name = select.value;
        if (!name) {
            alert("请先选择一个要删除的预设！");
            return;
        }
        if (!confirm(`确定要删除预设 "${name}" 吗？`)) return;
        try {
            let presets = {};
            const saved = localStorage.getItem('daoyuan_wx_presets');
            if (saved) presets = JSON.parse(saved);

            delete presets[name];
            localStorage.setItem('daoyuan_wx_presets', JSON.stringify(presets));
            window.loadPresets();
            alert(`预设 "${name}" 已删除！`);
        } catch(e) {
            alert("删除预设失败：" + e.message);
        }
    };

    window.loadWxSettings = function() {
        try {
            const saved = localStorage.getItem('daoyuan_wx_settings');
            if (saved) {
                const settings = JSON.parse(saved);
                const promptEl = document.getElementById('wx-custom-prompt');
                if (promptEl && settings.customPrompt !== undefined) promptEl.value = settings.customPrompt;

                if (settings.apiBaseUrl !== undefined) document.getElementById('wx-api-url').value = settings.apiBaseUrl;
                if (settings.apiKey !== undefined) document.getElementById('wx-api-key').value = settings.apiKey;
                if (settings.apiModel !== undefined) document.getElementById('wx-api-model').value = settings.apiModel;
            }
            window.loadPresets(); // 初始化预设列表
        } catch(e) {
            console.error('加载玉简设定失败:', e);
        }
    };

    /* 独立的世界书勾选保存逻辑 (只要 checkbox 变动或点按钮就触发) */
    window.saveWxLoreSettings = function() {
        const charName = window.currentActiveChat;
        if (!charName) return;

        let savedLore = {};
        try { savedLore = JSON.parse(localStorage.getItem('daoyuan_wx_lore_selected')) || {}; } catch(e){}

        const listContainer = document.getElementById('wx-lorebook-list');
        // 如果当前弹窗里没有渲染 checkbox，说明根本没加载出世界书，此时千万不要保存，以免误清空数据！
        if (!listContainer || !listContainer.innerHTML.includes('yujian-lore-checkbox')) {
            return;
        }

        const selectedCheckboxes = document.querySelectorAll('.yujian-lore-checkbox:checked');
        const selectedData = [];
        selectedCheckboxes.forEach(cb => {
            const uid = cb.value;
            if (window.currentLoreEntries) {
                // 【修复点】：使用 String() 强制转换对比，解决原来因类型不匹配（数字 vs 字符串）导致存入空数组的Bug
                const entry = window.currentLoreEntries.find(e => String(e.uid) === String(uid));
                if (entry) {
                    selectedData.push({ uid: uid, content: entry.content });
                }
            }
        });

        savedLore[charName] = selectedData;
        localStorage.setItem('daoyuan_wx_lore_selected', JSON.stringify(savedLore));
    };

    /* 基础设定保存逻辑 */
    window.saveWxSettings = function() {
        try {
            // 顺带再调用一次世界书保存，确保万无一失
            window.saveWxLoreSettings();

            const promptVal = document.getElementById('wx-custom-prompt').value;
            let savedSettings = {};
            try { savedSettings = JSON.parse(localStorage.getItem('daoyuan_wx_settings')) || {}; } catch(e){}

            savedSettings.customPrompt = promptVal;
            savedSettings.apiBaseUrl = document.getElementById('wx-api-url').value.trim();
            savedSettings.apiKey = document.getElementById('wx-api-key').value.trim();
            savedSettings.apiModel = document.getElementById('wx-api-model').value.trim();

            localStorage.setItem('daoyuan_wx_settings', JSON.stringify(savedSettings));
            document.getElementById('wx-prompt-modal').style.display = 'none';
        } catch(e) {
            alert('保存失败: ' + e.message);
        }
    };

    /* --- 获取可用模型列表 --- */
    window.fetchApiModels = async function() {
        const baseUrl = document.getElementById('wx-api-url').value.trim();
        const apiKey = document.getElementById('wx-api-key').value.trim();

        if (!baseUrl) {
            alert('请先填写基础 URL (Endpoint)！');
            return;
        }

        const btn = event.target;
        const originalText = btn.textContent;
        btn.textContent = '获取中...';
        btn.disabled = true;

        try {
            let url = baseUrl;
            if (url.endsWith('/chat/completions')) {
                url = url.replace('/chat/completions', '/models');
            } else {
                url = url.endsWith('/') ? url + 'models' : url + '/models';
            }

            const headers = {};
            if (apiKey) headers['Authorization'] = `Bearer ${apiKey}`;

            const response = await fetch(url, { headers });
            if (!response.ok) throw new Error(`HTTP ${response.status}`);

            const data = await response.json();
            const select = document.getElementById('wx-api-model-select');
            select.innerHTML = '<option value="">-- 选择模型 --</option>';

            if (data.data && Array.isArray(data.data)) {
                data.data.forEach(m => {
                    const opt = document.createElement('option');
                    opt.value = m.id;
                    opt.textContent = m.id;
                    select.appendChild(opt);
                });
                select.style.display = 'block';
            } else {
                alert('获取失败：返回的数据格式异常，不是标准的 OpenAI models 格式。');
            }
        } catch (err) {
            alert('获取模型列表失败: ' + err.message);
        } finally {
            btn.textContent = originalText;
            btn.disabled = false;
        }
    };

    /* --- 动态渲染与搜索世界书条目 --- */
    window.renderLorebooks = function(entries, filterText = '') {
        const listContainer = document.getElementById('wx-lorebook-list');
        if (!listContainer) return;

        let html = '';
        let savedLore = {};
        try { savedLore = JSON.parse(localStorage.getItem('daoyuan_wx_lore_selected')) || {}; } catch(e){}
        const charName = window.currentActiveChat;
        const selectedData = savedLore[charName] || [];
        // 【修复点】：渲染时也需要把 uid 转为字符串进行匹配
        const selectedUids = selectedData.map(d => String(d.uid));

        entries.forEach((entry, index) => {
            const displayName = entry.comment || (entry.key && entry.key.join(', ')) || '未命名条目';

            if (filterText) {
                const ft = filterText.toLowerCase();
                if (!displayName.toLowerCase().includes(ft) && !(entry.content && entry.content.toLowerCase().includes(ft))) {
                    return;
                }
            }

            // 【修复点】：判断是否 checked 时强制转字符串
            const isChecked = selectedUids.includes(String(entry.uid)) ? 'checked' : '';
            const safeContent = String(entry.content || '').replace(/&/g, '&').replace(/</g, '<').replace(/>/g, '>').replace(/"/g, '"');

            // onchange="window.saveWxLoreSettings()" 保证点一下立刻自动存本地
            html += `
                <div style="background: rgba(0,0,0,0.3); border-radius: 4px; border: 1px solid rgba(255,255,255,0.05); overflow: hidden; flex-shrink: 0;">
                    <label style="display: flex; gap: 8px; align-items: flex-start; cursor: pointer; color: var(--text-main); font-size: 0.85em; padding: 8px; transition: background 0.2s; margin: 0;">
                        <input type="checkbox" class="yujian-lore-checkbox" value="${entry.uid}" style="margin-top: 2px; cursor: pointer;" onchange="window.saveWxLoreSettings()" ${isChecked}>
                        <div style="flex: 1; display: flex; flex-direction: column;">
                            <span style="word-break: break-all; font-weight: bold; color: var(--accent-gold);">${displayName}</span>
                            <span style="font-size: 0.85em; color: var(--text-dim); margin-top: 2px;">来源: ${entry.lbName}</span>
                        </div>
                        <div onclick="event.preventDefault(); window.toggleLoreContent(${index}, this)" style="color: var(--accent-mana); cursor: pointer; padding: 0 5px; font-size: 1.2em; line-height: 1;" title="展开/折叠内容">▼</div>
                    </label>
                    <div id="lore-content-${index}" style="display: none; padding: 10px; border-top: 1px dashed rgba(255,255,255,0.1); font-size: 0.85em; color: var(--text-dim); white-space: pre-wrap; background: rgba(0,0,0,0.5); line-height: 1.5;">${safeContent}</div>
                </div>
            `;
        });
        if (!html) html = '<div style="color: var(--text-dim); font-style: italic; font-size: 0.85em; padding: 5px;">未找到匹配的世界书条目。</div>';
        listContainer.innerHTML = html;
    };

    window.filterLorebooks = function(text) {
        if (window.currentLoreEntries) {
            window.renderLorebooks(window.currentLoreEntries, text);
        }
    };

    window.toggleLoreContent = function(index, btn) {
        const el = document.getElementById('lore-content-' + index);
        if (el) {
            if (el.style.display === 'none') {
                el.style.display = 'block';
                if(btn) btn.innerHTML = '▲';
            } else {
                el.style.display = 'none';
                if(btn) btn.innerHTML = '▼';
            }
        }
    };

    /* --- 拉取全局及角色绑定的世界书条目 --- */
    window.openWxPromptModal = async function() {
        const modal = document.getElementById('wx-prompt-modal');
        // 强制显示并保证基础结构立即可见
        modal.style.display = 'flex';
        modal.style.zIndex = '99999';

        const charName = window.currentActiveChat;
        const listContainer = document.getElementById('wx-lorebook-list');

        if (!charName) {
            if(listContainer) listContainer.innerHTML = '<div style="color: var(--text-dim); font-style: italic; font-size: 0.85em;">请先在玉简中选择一个传讯对象并打开此面板。</div>';
            return;
        }

        if(listContainer) listContainer.innerHTML = '<div style="color: var(--accent-mana); font-style: italic; font-size: 0.85em;">正在拉取当前世界与角色的全部世界书设定...</div>';

        try {
            if (typeof getLorebookEntries !== 'function') {
                if(listContainer) listContainer.innerHTML = '<div style="color: var(--accent-blood); font-size: 0.85em;">当前环境不支持拉取世界书接口。</div>';
                return;
            }

            let lorebookNames = new Set();

            // 1. 尝试获取当前聊天的世界书
            if (typeof getOrCreateChatLorebook === 'function') {
                try {
                    const chatBook = await getOrCreateChatLorebook();
                    if (chatBook) lorebookNames.add(chatBook);
                } catch(e) { console.warn("获取聊天世界书失败", e); }
            }

            // 2. 尝试获取当前主角色绑定的主要世界书
            if (typeof getCurrentCharPrimaryLorebook === 'function') {
                try {
                    const primary = await getCurrentCharPrimaryLorebook();
                    if (primary) lorebookNames.add(primary);
                } catch(e) { console.warn("获取主角色世界书失败", e); }
            }

            // 3. 尝试获取当前传讯对象绑定的世界书
            if (typeof getCharLorebooks === 'function') {
                try {
                    const charBooks = await getCharLorebooks({ name: charName });
                    if (charBooks && charBooks.length > 0) {
                        charBooks.forEach(b => lorebookNames.add(b));
                    }
                } catch(e) { console.warn("获取传讯对象世界书失败", e); }
            }

            if (lorebookNames.size === 0) {
                if(listContainer) listContainer.innerHTML = '<div style="color: var(--text-dim); font-style: italic; font-size: 0.85em;">当前聊天和角色均未绑定任何世界书。</div>';
                return;
            }

            let allEntries = [];
            for (const lbName of lorebookNames) {
                try {
                    const entries = await getLorebookEntries(lbName, { fields: ['uid', 'comment', 'key', 'content'] });
                    if (entries && entries.length > 0) {
                        allEntries = allEntries.concat(entries.map(e => ({...e, lbName})));
                    }
                } catch(e) {
                    console.warn(`拉取世界书 [${lbName}] 失败`, e);
                }
            }

            // 去重（按 content 去重，防止不同世界书里有重复条目）
            const uniqueEntries = [];
            const contentSet = new Set();
            allEntries.forEach(e => {
                if (e.content && !contentSet.has(e.content)) {
                    contentSet.add(e.content);
                    uniqueEntries.push(e);
                }
            });

            if (uniqueEntries.length === 0) {
                if(listContainer) listContainer.innerHTML = '<div style="color: var(--text-dim); font-style: italic; font-size: 0.85em;">绑定的世界书中未找到任何有效条目。</div>';
                return;
            }

            window.currentLoreEntries = uniqueEntries;
            const searchInput = document.getElementById('wx-lore-search');
            if (searchInput) searchInput.value = '';
            window.renderLorebooks(uniqueEntries, '');

        } catch (err) {
            console.error("拉取世界书失败:", err);
            if(listContainer) listContainer.innerHTML = '<div style="color: var(--accent-blood); font-size: 0.85em;">拉取世界书失败，请检查控制台报错。</div>';
        }
    };

    /* --- 核心生成请求提取 (防空回 + 兼容API + 解决截断) --- */
    window.callGenerateReply = async function(injectContent, userMessage, charName) {
        let finalReply = "";
        let settings = {};
        try {
            const saved = localStorage.getItem('daoyuan_wx_settings');
            if (saved) settings = JSON.parse(saved);
        } catch(e) {}

        const systemPrompt = injectContent + `\n\n(请以【${charName}】的身份回复，严格只输出纯对话内容，绝对不要带角色名、引号、动作描写或[]符号。)`;

        if (settings.apiBaseUrl && settings.apiModel) {
            // 使用自定义 API
            let endpoint = settings.apiBaseUrl;
            if (!endpoint.endsWith('/chat/completions') && !endpoint.endsWith('/chat/completions/')) {
                endpoint = endpoint.endsWith('/') ? endpoint + 'chat/completions' : endpoint + '/chat/completions';
            }

            // 增加 max_tokens 防止被截断，针对部分模型增加 temperature
            const payload = {
                model: settings.apiModel,
                messages: [
                    { role: "system", content: systemPrompt },
                    { role: "user", content: userMessage }
                ],
                temperature: 0.7,
                max_tokens: 2000
            };

            const headers = { 'Content-Type': 'application/json' };
            if (settings.apiKey) headers['Authorization'] = `Bearer ${settings.apiKey}`;

            try {
                const response = await fetch(endpoint, {
                    method: 'POST',
                    headers: headers,
                    body: JSON.stringify(payload)
                });
                if (!response.ok) {
                    const errText = await response.text();
                    throw new Error(`API 请求失败: ${response.status} - ${errText}`);
                }
                const data = await response.json();
                if (data.choices && data.choices.length > 0 && data.choices[0].message) {
                    finalReply = data.choices[0].message.content;
                } else {
                    throw new Error(`API 返回格式异常: ${JSON.stringify(data)}`);
                }
            } catch (e) {
                console.error("自定义API调用失败:", e);
                window.updateDebugLog(`❌ 请求报错:\n${e.message}`);
                alert("自定义API调用失败，请查看「玉简设定」中的日志排查问题。");
                throw e;
            }
        } else {
            // 使用酒馆原生 generate
            if (typeof generate === 'function') {
                try {
                    const combinedPrompt = systemPrompt + "\n\n" + userMessage;
                    const rawReply = await generate({
                        user_input: combinedPrompt,
                        should_stream: false,
                        max_chat_history: 15
                    });

                    if (typeof rawReply === 'string') {
                        finalReply = rawReply;
                    } else if (rawReply && rawReply.text) {
                        finalReply = rawReply.text;
                    } else if (rawReply && rawReply.reply) {
                        finalReply = rawReply.reply;
                    } else {
                        finalReply = String(rawReply || "");
                    }
                } catch(e) {
                    console.error("调用酒馆生成失败:", e);
                    window.updateDebugLog(`❌ 酒馆原生生成报错:\n${e.message}`);
                    alert("调用酒馆生成失败，请检查助手配置。");
                    throw e;
                }
            } else {
                alert("⚠️ 未检测到酒馆 generate 函数，且未配置自定义 API。");
                throw new Error("无可用生成接口");
            }
        }

        console.log('[玉简] AI返回的原始内容:', finalReply);
        // 把真实返回内容写进 UI 日志里
        window.updateDebugLog(finalReply || "(空返回)");

        // --- 防空回及提取逻辑 ---
        if (!finalReply || finalReply.trim() === "") {
            return "对方似乎没有想好怎么回复...";
        }

        let extracted = finalReply;

        // 1. 彻底剔除 <think> 思考过程 (匹配包含换行的所有内容)
        extracted = extracted.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();

        // 2. 尝试提取 [REPLY] 标签
        const replyMatch = extracted.match(/\[REPLY\]([\s\S]*?)\[\/REPLY\]/i) ||
                           extracted.match(/【回复】([\s\S]*?)【\/回复】/);

        if (replyMatch && replyMatch[1]) {
            extracted = replyMatch[1].trim();
        } else {
            // 3. 增强的清洗逻辑：没有标签时，保留过滤 think 后的完整内容
            // 去除角色名前缀 (例如 "瑶汐:", "【瑶汐】:", "瑶汐说：")
            const prefixRegex = new RegExp(`^(?:【?${charName}】?\\s*(?:说)?\\s*[:：\\n])`, 'i');
            extracted = extracted.replace(prefixRegex, '').trim();
            // 去除最外层的引号
            extracted = extracted.replace(/^[<q>"'「”]|["</q>'」]$/g, '').trim();
        }

        if (!extracted) {
            extracted = "对方传来了模糊不清的神念...";
        }

        return extracted;
    };

    window.handleReply = async function(buttonElement, charName) {
        const all_variables = getAllVariables();
        const sanCurrent = parseFloat(_.get(all_variables, 'stat_data.主角.神识', 0));

        if (sanCurrent < 20) {
            alert('神识不足20，无法传讯！');
            return;
        }

        const container = buttonElement.parentElement;
        const inputElement = container.querySelector('.reply-input');
        const replyText = inputElement.value.trim();

        if (!replyText) {
            alert('回复内容不能为空！');
            return;
        }

        /* 写入"我"的消息 */
        inputElement.value = '';
        inputElement.style.height = 'auto';
        buttonElement.disabled = true;
        buttonElement.textContent = '发送中...';

        await window.appendChatMessage(charName, '我', replyText);

        const fullData = _.get(all_variables, 'stat_data', {});
        const historyObj = (fullData.玉简 && fullData.玉简[charName] && fullData.玉简[charName].历史记录) || {};

        let historyText = "";
        Object.values(historyObj).forEach(msg => {
            historyText += `[${msg.发送者}]: ${msg.内容}\n`;
        });
        const customPrompt = document.getElementById('wx-custom-prompt') ? document.getElementById('wx-custom-prompt').value.trim() : '';

        // ++ 从最新的独立存储中提取勾选的世界书知识 ++
        let activeLoreContext = '';
        let savedLore = {};
        try { savedLore = JSON.parse(localStorage.getItem('daoyuan_wx_lore_selected')) || {}; } catch(e){}
        const selectedData = savedLore[charName] || [];
        selectedData.forEach(data => {
            if (data.content) activeLoreContext += data.content + '\n\n';
        });

        // --- 新增：提取主角与对方的状态变量 ---
        const stat = _.get(all_variables, 'stat_data', {});
        const hero = stat.主角 || {};
        const world = stat.世界 || {};

        let heroInfo = `[主角当前状态]\n境界: ${hero.境界 || '未知'}\n所在界域: ${hero.所在界 || '未知'}\n当前地点: ${world.当前地点 || '未知'}\n当前时间: ${world.当前时间 || '未知'}\n灵根: ${hero.灵根 || '无'}\n`;
        const skills = hero.功法 || {};
        const skillNames = Object.entries(skills).map(([k, v]) => `${k}(${v.境界 || '未知'})`).join('、');
        heroInfo += `功法: ${skillNames || '无'}`;

        let charSelfInfo = '\n\n[你的当前状态/面板设定]\n';
        const partnerData = (stat.道侣 || {})[charName];
        const npcData = (stat.人物 || {})[charName];
        const petData = (stat.灵宠 || {})[charName];
        const targetData = partnerData || npcData || petData || {};

        const yujianData = (stat.玉简 || {})[charName] || {};
        const mergedData = { ...targetData };

        if (yujianData.境界) mergedData['境界'] = yujianData.境界;
        if (yujianData.性别) mergedData['性别'] = yujianData.性别;
        if (yujianData.关系) mergedData['关系'] = yujianData.关系;
        if (yujianData.好感度) mergedData['好感度'] = yujianData.好感度;

        let hasData = false;
        Object.entries(mergedData).forEach(([k, v]) => {
            if (typeof v !== 'object' && v !== undefined && v !== null) {
                charSelfInfo += `${k}: ${v}\n`;
                hasData = true;
            }
        });

        if (!hasData) {
            charSelfInfo = '';
        }
        // ------------------------------------

        let injectContent = `[玉简传讯历史记录]\n${historyText}`;
        if (customPrompt) {
            injectContent += `\n\n【附加设定/规则】\n${customPrompt}`;
        }
        if (activeLoreContext) {
            injectContent += `\n\n【角色已知世界书背景】\n${activeLoreContext}`;
        }

        // 注入主角面板与对方自身面板数据
        injectContent += `\n\n${heroInfo}${charSelfInfo}`;

        buttonElement.textContent = '对方输入中';

        try {
            const finalReply = await window.callGenerateReply(injectContent, `[玉简传讯系统] 主角发来最新传讯：\n"${replyText}"`, charName);
            await window.appendChatMessage(charName, charName, finalReply);
        } catch (e) {
            // 错误已经在 callGenerateReply 内部抛出并提示
        }

        buttonElement.textContent = '发送';
        buttonElement.disabled = false;
    };

    /* ===== 单条消息操作: 删除 与 重试 ===== */
    window.deleteSingleMessage = async function(charName, msgId) {
        if(!confirm('确定删除这条传讯吗？')) return;
        try {
            const lastMsgId = getLastMessageId();
            const messages = getChatMessages('0-' + lastMsgId, { role: 'assistant' });
            if (!messages || messages.length === 0) return;
            const targetMsgId = messages[messages.length - 1].message_id;

            if (window.Mvu && typeof Mvu.replaceMvuData === 'function') {
                const fullData = Mvu.getMvuData({ type: 'message', message_id: targetMsgId });
                if (fullData && fullData.stat_data && fullData.stat_data.玉简 && fullData.stat_data.玉简[charName] && fullData.stat_data.玉简[charName].历史记录) {
                    delete fullData.stat_data.玉简[charName].历史记录[msgId];
                    await Mvu.replaceMvuData(fullData, { type: 'message', message_id: targetMsgId });

                    window.currentMessagesData[charName].历史记录 = fullData.stat_data.玉简[charName].历史记录;
                    window.openChatView(charName);
                }
            }
        } catch (err) {
            console.error('删除单条消息失败:', err);
        }
    };

    window.retrySingleMessage = async function(charName, msgId) {
        if(!confirm('确定要重试生成这条回复吗？（该条记录将被删除，并重新请求附在最后）')) return;
        try {
            const lastMsgId = getLastMessageId();
            const messages = getChatMessages('0-' + lastMsgId, { role: 'assistant' });
            const targetMsgId = messages[messages.length - 1].message_id;

            let historyObj = {};
            if (window.Mvu && typeof Mvu.replaceMvuData === 'function') {
                const fullData = Mvu.getMvuData({ type: 'message', message_id: targetMsgId });
                if (fullData && fullData.stat_data && fullData.stat_data.玉简 && fullData.stat_data.玉简[charName] && fullData.stat_data.玉简[charName].历史记录) {
                    historyObj = { ...fullData.stat_data.玉简[charName].历史记录 };
                    delete historyObj[msgId];
                    fullData.stat_data.玉简[charName].历史记录 = historyObj;
                    await Mvu.replaceMvuData(fullData, { type: 'message', message_id: targetMsgId });

                    window.currentMessagesData[charName].历史记录 = historyObj;
                    window.openChatView(charName);
                }
            }

            const btn = document.getElementById('wx-reply-btn');
            if(btn) {
                btn.textContent = '正在重写...';
                btn.disabled = true;
            }

            let historyText = "";
            Object.values(historyObj).forEach(msg => {
                historyText += `[${msg.发送者}]: ${msg.内容}\n`;
            });
            const customPrompt = document.getElementById('wx-custom-prompt') ? document.getElementById('wx-custom-prompt').value.trim() : '';

            // ++ 重试时同样提取最新的独立世界书数据 ++
            let activeLoreContext = '';
            let savedLore = {};
            try { savedLore = JSON.parse(localStorage.getItem('daoyuan_wx_lore_selected')) || {}; } catch(e){}
            const selectedData = savedLore[charName] || [];
            selectedData.forEach(data => {
                if (data.content) activeLoreContext += data.content + '\n\n';
            });

            // --- 新增：提取主角与对方的状态变量 ---
            const all_variables = getAllVariables();
            const stat = _.get(all_variables, 'stat_data', {});
            const hero = stat.主角 || {};
            const world = stat.世界 || {};

            let heroInfo = `[主角当前状态]\n境界: ${hero.境界 || '未知'}\n所在界域: ${hero.所在界 || '未知'}\n当前地点: ${world.当前地点 || '未知'}\n当前时间: ${world.当前时间 || '未知'}\n灵根: ${hero.灵根 || '无'}\n`;
            const skills = hero.功法 || {};
            const skillNames = Object.entries(skills).map(([k, v]) => `${k}(${v.境界 || '未知'})`).join('、');
            heroInfo += `功法: ${skillNames || '无'}`;

            let charSelfInfo = '\n\n[你的当前状态/面板设定]\n';
            const partnerData = (stat.道侣 || {})[charName];
            const npcData = (stat.人物 || {})[charName];
            const petData = (stat.灵宠 || {})[charName];
            const targetData = partnerData || npcData || petData || {};

            const yujianData = (stat.玉简 || {})[charName] || {};
            const mergedData = { ...targetData };

            if (yujianData.境界) mergedData['境界'] = yujianData.境界;
            if (yujianData.性别) mergedData['性别'] = yujianData.性别;
            if (yujianData.关系) mergedData['关系'] = yujianData.关系;
            if (yujianData.好感度) mergedData['好感度'] = yujianData.好感度;

            let hasData = false;
            Object.entries(mergedData).forEach(([k, v]) => {
                if (typeof v !== 'object' && v !== undefined && v !== null) {
                    charSelfInfo += `${k}: ${v}\n`;
                    hasData = true;
                }
            });

            if (!hasData) {
                charSelfInfo = '';
            }
            // ------------------------------------

            let injectContent = `[玉简传讯历史记录]\n${historyText}`;
            if (customPrompt) {
                injectContent += `\n\n【附加设定/规则】\n${customPrompt}`;
            }
            if (activeLoreContext) {
                injectContent += `\n\n【角色已知世界书背景】\n${activeLoreContext}`;
            }

            // 注入主角面板与对方自身面板数据
            injectContent += `\n\n${heroInfo}${charSelfInfo}`;

            const finalReply = await window.callGenerateReply(injectContent, `[玉简传讯系统] 请继续通过玉简传讯回复主角的上一条消息。`, charName);
            await window.appendChatMessage(charName, charName, finalReply);

            if(btn) {
                btn.textContent = '发送';
                btn.disabled = false;
            }
        } catch(err) {
            console.error('重试失败:', err);
            const btn = document.getElementById('wx-reply-btn');
            if(btn) { btn.textContent = '发送'; btn.disabled = false; }
        }
